1	import { useCallback, useEffect, useMemo, useState } from 'react';
2	import {
3	  ActivityIndicator,
4	  KeyboardAvoidingView,
5	  Platform as RNPlatform,
6	  SafeAreaView,
7	  ScrollView,
8	  StyleSheet,
9	  Text,
10	  TextInput,
11	  View,
12	} from 'react-native';
13	import { BottomSheet } from '@/components/primitives/BottomSheet';
14	import { ButtonPrimary, ButtonSecondary } from '@/components/primitives/Button';
15	import { useToast } from '@/components/primitives/Toast';
16	import { colors, radii, shadows, spacing } from '@/design/tokens';
17	import { textStyles } from '@/design/typography';
18	import { useAuth } from '@/lib/auth';
19	import { supabase } from '@/lib/supabase';
20	import { formatRelativeTime } from '@/lib/time';
21	import type { Database } from '@/types/supabase';
22	
23	// US-035 — creator profile. Shows TikTok + Instagram handles with their
24	// denormalized follower counts / avg views, a "Stale" chip when the latest
25	// metric_snapshot was flipped to status='stale' by the hourly cron, and an
26	// Add / Unlink flow wired to the manage-social-link edge function.
27	//
28	// Spec gap: the story AC says "Stale chip appears when metrics_stale_at is
29	// non-null", but there is no metrics_stale_at column on creator_profiles
30	// (see us_004 + the us_011 cron which flips metric_snapshots.status='stale'
31	// instead). The chip is therefore derived from
32	// metric_snapshots WHERE is_latest = true AND status = 'stale', which is
33	// the signal the cron actually produces per docs/tech-architecture.md §16.
34	//
35	// Apify scrapes on add are deferred to US-036 (pull-to-refresh) to keep
36	// this story focused on the CRUD flow — matches the story AC wording
37	// ("small edge function").
38	
39	type SocialPlatform = Database['public']['Enums']['platform'];
40	type SocialLink = Database['public']['Tables']['social_links']['Row'];
41	type CreatorProfileRow = Database['public']['Tables']['creator_profiles']['Row'];
42	
43	const HANDLE_RE = /^[a-zA-Z0-9_.]{1,30}$/;
44	const PLATFORMS: readonly SocialPlatform[] = ['tiktok', 'instagram'];
45	
46	export default function CreatorProfile() {
47	  const { user, signOut } = useAuth();
48	  const { show: showToast } = useToast();
49	
50	  const [profile, setProfile] = useState<CreatorProfileRow | null>(null);
51	  const [links, setLinks] = useState<SocialLink[]>([]);
52	  const [staleLinkIds, setStaleLinkIds] = useState<Set<string>>(new Set());
53	  const [loading, setLoading] = useState(true);
54	  const [pendingAction, setPendingAction] = useState<string | null>(null);
55	  const [sheetPlatform, setSheetPlatform] = useState<SocialPlatform | null>(null);
56	
57	  const load = useCallback(async () => {
58	    if (!user) return;
59	    setLoading(true);
60	    try {
61	      const [profileRes, linksRes, snapsRes] = await Promise.all([
62	        supabase
63	          .from('creator_profiles')
64	          .select('*')
65	          .eq('user_id', user.id)
66	          .maybeSingle(),
67	        supabase
68	          .from('social_links')
69	          .select('*')
70	          .eq('user_id', user.id)
71	          .neq('status', 'unlinked'),
72	        supabase
73	          .from('metric_snapshots')
74	          .select('social_link_id, status')
75	          .eq('is_latest', true)
76	          .eq('status', 'stale'),
77	      ]);
78	      if (profileRes.error) throw profileRes.error;
79	      if (linksRes.error) throw linksRes.error;
80	      if (snapsRes.error) throw snapsRes.error;
81	      setProfile(profileRes.data ?? null);
82	      setLinks(linksRes.data ?? []);
83	      setStaleLinkIds(new Set((snapsRes.data ?? []).map((r) => r.social_link_id)));
84	    } catch (err) {
85	      console.error('Profile load failed', err);
86	      showToast({ message: 'Could not load profile.', variant: 'error' });
87	    } finally {
88	      setLoading(false);
89	    }
90	  }, [user, showToast]);
91	
92	  useEffect(() => {
93	    void load();
94	  }, [load]);
95	
96	  const sections = useMemo(() => {
97	    return PLATFORMS.map((platform) => {
98	      const link = links.find((l) => l.platform === platform) ?? null;
99	      const isStale = link ? staleLinkIds.has(link.id) : false;
100	      return { platform, link, isStale };
101	    });
102	  }, [links, staleLinkIds]);
103	
104	  const onAdd = useCallback(
105	    async (platform: SocialPlatform, rawHandle: string) => {
106	      const handle = rawHandle.trim().replace(/^@+/, '').trim();
107	      if (!HANDLE_RE.test(handle)) {
108	        showToast({
109	          message: 'Handle must be letters, numbers, underscores, or dots.',
110	          variant: 'error',
111	        });
112	        return;
113	      }
114	      setPendingAction(`add:${platform}`);
115	      try {
116	        const { data, error } = await supabase.functions.invoke<{ social_link_id: string }>(
117	          'manage-social-link',
118	          { body: { action: 'add', platform, handle } },
119	        );
120	        if (error) {
121	          const ctx = (error as { context?: unknown }).context;
122	          if (
123	            ctx &&
124	            typeof ctx === 'object' &&
125	            'status' in ctx &&
126	            typeof (ctx as { json?: unknown }).json === 'function'
127	          ) {
128	            const res = ctx as Response;
129	            let body: { error?: string } = {};
130	            try {
131	              body = (await res.json()) as { error?: string };
132	            } catch {
133	              // non-JSON body — fall through to generic toast
134	            }
135	            if (res.status === 409 && body.error === 'ALREADY_LINKED') {
136	              showToast({
137	                message: `You already have a ${platformLabel(platform)} handle linked.`,
138	                variant: 'error',
139	              });
140	              return;
141	            }
142	            if (res.status === 409 && body.error === 'HANDLE_TAKEN') {
143	              showToast({
144	                message: 'That handle is already linked to another account.',
145	                variant: 'error',
146	              });
147	              return;
148	            }
149	          }
150	          showToast({ message: 'Could not add handle.', variant: 'error' });
151	          return;
152	        }
153	        if (!data?.social_link_id) {
154	          showToast({ message: 'Could not add handle.', variant: 'error' });
155	          return;
156	        }
157	        setSheetPlatform(null);
158	        showToast({
159	          message: `${platformLabel(platform)} handle added.`,
160	          variant: 'success',
161	        });
162	        await load();
163	      } finally {
164	        setPendingAction(null);
165	      }
166	    },
167	    [showToast, load],
168	  );
169	
170	  const onUnlink = useCallback(
171	    async (link: SocialLink) => {
172	      setPendingAction(`unlink:${link.id}`);
173	      try {
174	        const { error } = await supabase.functions.invoke('manage-social-link', {
175	          body: { action: 'unlink', social_link_id: link.id },
176	        });
177	        if (error) {
178	          showToast({ message: 'Could not unlink handle.', variant: 'error' });
179	          return;
180	        }
181	        showToast({
182	          message: `${platformLabel(link.platform)} handle unlinked.`,
183	          variant: 'success',
184	        });
185	        await load();
186	      } finally {
187	        setPendingAction(null);
188	      }
189	    },
190	    [showToast, load],
191	  );
192	
193	  return (
194	    <SafeAreaView style={styles.container}>
195	      <ScrollView contentContainerStyle={styles.scrollContent}>
196	        <View style={styles.header}>
197	          <Text style={[textStyles.display, { color: colors.ink }]}>Profile</Text>
198	          {user ? (
199	            <Text style={[textStyles.mono, styles.usernameRow]}>@{user.username}</Text>
200	          ) : null}
201	        </View>
202	
203	        {loading && profile === null ? (
204	          <View style={styles.loadingBlock}>
205	            <ActivityIndicator color={colors.ink} />
206	          </View>
207	        ) : (
208	          <View style={styles.sections}>
209	            {sections.map(({ platform, link, isStale }) => (
210	              <PlatformCard
211	                key={platform}
212	                platform={platform}
213	                link={link}
214	                profile={profile}
215	                isStale={isStale}
216	                pendingAction={pendingAction}
217	                onOpenAdd={() => setSheetPlatform(platform)}
218	                onUnlink={onUnlink}
219	              />
220	            ))}
221	          </View>
222	        )}
223	
224	        <View style={styles.signOutWrap}>
225	          <ButtonSecondary
226	            label="Sign out"
227	            onPress={signOut}
228	            accessibilityLabel="Sign out"
229	            testID="creator-signout"
230	          />
231	        </View>
232	      </ScrollView>
233	
234	      <AddHandleSheet
235	        platform={sheetPlatform}
236	        onDismiss={() => setSheetPlatform(null)}
237	        onSubmit={onAdd}
238	        submitting={sheetPlatform !== null && pendingAction === `add:${sheetPlatform}`}
239	      />
240	    </SafeAreaView>
241	  );
242	}
243	
244	type PlatformCardProps = {
245	  platform: SocialPlatform;
246	  link: SocialLink | null;
247	  profile: CreatorProfileRow | null;
248	  isStale: boolean;
249	  pendingAction: string | null;
250	  onOpenAdd: () => void;
251	  onUnlink: (link: SocialLink) => void;
252	};
253	
254	function PlatformCard({
255	  platform,
256	  link,
257	  profile,
258	  isStale,
259	  pendingAction,
260	  onOpenAdd,
261	  onUnlink,
262	}: PlatformCardProps) {
263	  const { follower, avgViews } = extractMetrics(platform, profile);
264	  const lastRefreshedLabel = profile?.metrics_fetched_at
265	    ? formatRelativeTime(new Date(profile.metrics_fetched_at))
266	    : 'Never';
267	  const unlinkLoading = link ? pendingAction === `unlink:${link.id}` : false;
268	
269	  return (
270	    <View style={styles.card}>
271	      <View style={styles.cardHeader}>
272	        <Text style={[textStyles.h2, { color: colors.ink }]}>{platformLabel(platform)}</Text>
273	        {isStale && link ? <StaleChip /> : null}
274	      </View>
275	
276	      {link ? (
277	        <>
278	          <Text style={[textStyles.mono, styles.handleRow]}>@{link.handle}</Text>
279	          <View style={styles.metricsRow}>
280	            <Metric label="Followers" value={formatCount(follower)} />
281	            <Metric label="Avg views" value={formatCount(avgViews)} />
282	          </View>
283	          <Text style={[textStyles.caption, styles.lastRefreshed]}>
284	            Last refreshed {lastRefreshedLabel}
285	          </Text>
286	          <View style={styles.cardAction}>
287	            <ButtonSecondary
288	              label="Unlink handle"
289	              onPress={() => onUnlink(link)}
290	              loading={unlinkLoading}
291	              disabled={unlinkLoading}
292	              accessibilityLabel={`Unlink ${platformLabel(platform)} handle`}
293	              testID={`unlink-${platform}`}
294	            />
295	          </View>
296	        </>
297	      ) : (
298	        <>
299	          <Text style={[textStyles.body, styles.emptyRow]}>
300	            No {platformLabel(platform)} handle linked.
301	          </Text>
302	          <View style={styles.cardAction}>
303	            <ButtonPrimary
304	              label={`Add ${platformLabel(platform)} handle`}
305	              onPress={onOpenAdd}
306	              accessibilityLabel={`Add ${platformLabel(platform)} handle`}
307	              testID={`add-${platform}`}
308	            />
309	          </View>
310	        </>
311	      )}
312	    </View>
313	  );
314	}
315	
316	function Metric({ label, value }: { label: string; value: string }) {
317	  return (
318	    <View style={styles.metric}>
319	      <Text style={[textStyles.caption, { color: colors.ink70 }]}>{label}</Text>
320	      <Text style={[textStyles.h1, { color: colors.ink }]}>{value}</Text>
321	    </View>
322	  );
323	}
324	
325	function StaleChip() {
326	  return (
327	    <View
328	      style={[styles.stalePill, shadows.hard]}
329	      accessible
330	      accessibilityLabel="Metrics are stale"
331	      testID="stale-chip"
332	    >
333	      <Text style={[textStyles.micro, { color: colors.warning }]} allowFontScaling={false}>
334	        Stale
335	      </Text>
336	    </View>
337	  );
338	}
339	
340	function AddHandleSheet({
341	  platform,
342	  onDismiss,
343	  onSubmit,
344	  submitting,
345	}: {
346	  platform: SocialPlatform | null;
347	  onDismiss: () => void;
348	  onSubmit: (platform: SocialPlatform, handle: string) => void;
349	  submitting: boolean;
350	}) {
351	  const [value, setValue] = useState('');
352	  useEffect(() => {
353	    if (platform !== null) setValue('');
354	  }, [platform]);
355	
356	  return (
357	    <BottomSheet
358	      visible={platform !== null}
359	      onDismiss={onDismiss}
360	      snapPoints={[0.5]}
361	      accessibilityLabel="Add handle"
362	    >
363	      {platform ? (
364	        <KeyboardAvoidingView
365	          behavior={RNPlatform.OS === 'ios' ? 'padding' : undefined}
366	          style={styles.sheetBody}
367	        >
368	          <Text style={[textStyles.h1, { color: colors.ink }]}>
369	            Add {platformLabel(platform)} handle
370	          </Text>
371	          <Text style={[textStyles.body, styles.sheetHint]}>
372	            We&apos;ll pull your latest stats on next refresh.
373	          </Text>
374	          <View style={[styles.inputWrap, shadows.hard]}>
375	            <TextInput
376	              value={value}
377	              onChangeText={setValue}
378	              autoCapitalize="none"
379	              autoCorrect={false}
380	              autoComplete="off"
381	              placeholder={platform === 'tiktok' ? '@yourtiktok' : '@yourinsta'}
382	              placeholderTextColor={colors.ink40}
383	              style={[textStyles.mono, styles.input]}
384	              editable={!submitting}
385	              accessibilityLabel={`${platformLabel(platform)} handle`}
386	              testID={`sheet-handle-input-${platform}`}
387	            />
388	          </View>
389	          <ButtonPrimary
390	            label="Add handle"
391	            onPress={() => onSubmit(platform, value)}
392	            loading={submitting}
393	            disabled={submitting || value.trim().length === 0}
394	            accessibilityLabel={`Add ${platformLabel(platform)} handle`}
395	            testID={`sheet-add-${platform}`}
396	          />
397	        </KeyboardAvoidingView>
398	      ) : null}
399	    </BottomSheet>
400	  );
401	}
402	
403	function extractMetrics(
404	  platform: SocialPlatform,
405	  profile: CreatorProfileRow | null,
406	): { follower: number | null; avgViews: number | null } {
407	  if (!profile) return { follower: null, avgViews: null };
408	  if (platform === 'tiktok') {
409	    return {
410	      follower: profile.tiktok_follower_count,
411	      avgViews: profile.tiktok_avg_views_last_10,
412	    };
413	  }
414	  return {
415	    follower: profile.instagram_follower_count,
416	    avgViews: profile.instagram_avg_views_last_10,
417	  };
418	}
419	
420	function platformLabel(p: SocialPlatform): string {
421	  return p === 'tiktok' ? 'TikTok' : 'Instagram';
422	}
423	
424	function formatCount(n: number | null): string {
425	  if (n === null) return '—';
426	  if (n < 1000) return String(n);
427	  if (n < 1_000_000) return `${(n / 1000).toFixed(n < 10_000 ? 1 : 0)}k`;
428	  return `${(n / 1_000_000).toFixed(n < 10_000_000 ? 1 : 0)}m`;
429	}
430	
431	const styles = StyleSheet.create({
432	  container: {
433	    flex: 1,
434	    backgroundColor: colors.canvas,
435	  },
436	  scrollContent: {
437	    padding: spacing.base,
438	    gap: spacing.xl,
439	    paddingBottom: spacing.xxxl,
440	  },
441	  header: {
442	    gap: spacing.xs,
443	    paddingTop: spacing.base,
444	  },
445	  usernameRow: {
446	    color: colors.ink70,
447	  },
448	  loadingBlock: {
449	    alignItems: 'center',
450	    paddingVertical: spacing.xxl,
451	  },
452	  sections: {
453	    gap: spacing.base,
454	  },
455	  card: {
456	    backgroundColor: colors.surface,
457	    borderColor: colors.ink,
458	    borderWidth: 2,
459	    borderRadius: radii.card,
460	    padding: spacing.base,
461	    ...shadows.hard,
462	  },
463	  cardHeader: {
464	    flexDirection: 'row',
465	    justifyContent: 'space-between',
466	    alignItems: 'center',
467	    gap: spacing.sm,
468	  },
469	  handleRow: {
470	    color: colors.ink,
471	    marginTop: spacing.sm,
472	  },
473	  metricsRow: {
474	    flexDirection: 'row',
475	    gap: spacing.xl,
476	    marginTop: spacing.md,
477	  },
478	  metric: {
479	    gap: spacing.xs,
480	  },
481	  lastRefreshed: {
482	    color: colors.ink70,
483	    marginTop: spacing.md,
484	  },
485	  emptyRow: {
486	    color: colors.ink70,
487	    marginTop: spacing.sm,
488	  },
489	  cardAction: {
490	    marginTop: spacing.md,
491	  },
492	  stalePill: {
493	    backgroundColor: colors.warningSoft,
494	    borderColor: colors.warning,
495	    borderWidth: 2,
496	    borderRadius: radii.pill,
497	    paddingHorizontal: spacing.md,
498	    paddingVertical: 4,
499	  },
500	  signOutWrap: {
501	    paddingTop: spacing.md,
502	  },
