1	// Edge function: manage-social-link (US-035)
2	//
3	// Contract:
4	//   POST add:    { action: 'add', platform: 'tiktok'|'instagram', handle: string }
5	//     → 200 { social_link_id: string }
6	//   POST unlink: { action: 'unlink', social_link_id: string }
7	//     → 200 { ok: true }
8	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
9	//     → 401 { error: 'UNAUTHORIZED' }
10	//     → 403 { error: 'FORBIDDEN' }
11	//     → 404 { error: 'LINK_NOT_FOUND' }
12	//     → 409 { error: 'ALREADY_LINKED' | 'HANDLE_TAKEN' }
13	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
14	//
15	// Auth: Marketify JWT (HS256, MARKETIFY_JWT_SECRET). Verifies via
16	//       _shared/jwt.ts and asserts role='creator'. Deployed with
17	//       verify_jwt=false at the gateway; the handler enforces auth.
18	//
19	// Atomicity: single INSERT (add) or single UPDATE (unlink) inside the
20	// public.manage_social_link RPC's implicit transaction.
21	//
22	// Scope: this function does NOT kick Apify scrapes on add. Pulling metrics
23	// for a freshly-added handle is the job of US-036 (pull-to-refresh on
24	// Profile) — a pattern identical to metrics-refresh. Keeping scope tight
25	// here matches the story AC ("Add Handle / Unlink Handle actions wired to
26	// a small edge function").
27	
28	import { createClient } from "npm:@supabase/supabase-js@2";
29	import { verifyJwt } from "../_shared/jwt.ts";
30	import { corsHeaders } from "../_shared/cors.ts";
31	
32	const UUID_RE =
33	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
34	const HANDLE_RE = /^[a-zA-Z0-9_.]{1,30}$/;
35	
36	type Platform = "tiktok" | "instagram";
37	
38	interface AddRequest {
39	  action?: "add";
40	  platform?: unknown;
41	  handle?: unknown;
42	}
43	interface UnlinkRequest {
44	  action?: "unlink";
45	  social_link_id?: unknown;
46	}
47	type AnyRequest = AddRequest | UnlinkRequest | { action?: unknown };
48	
49	function jsonResponse(status: number, body: unknown): Response {
50	  return new Response(JSON.stringify(body), {
51	    status,
52	    headers: { ...corsHeaders, "Content-Type": "application/json" },
53	  });
54	}
55	
56	function bearerToken(req: Request): string | null {
57	  const raw = req.headers.get("Authorization") ??
58	    req.headers.get("authorization");
59	  if (!raw) return null;
60	  const m = raw.match(/^Bearer\s+(.+)$/i);
61	  return m ? m[1].trim() : null;
62	}
63	
64	function normalizeHandle(value: unknown): string | null {
65	  if (typeof value !== "string") return null;
66	  const stripped = value.trim().replace(/^@+/, "").trim();
67	  if (stripped.length === 0 || !HANDLE_RE.test(stripped)) return null;
68	  return stripped;
69	}
70	
71	function parsePlatform(value: unknown): Platform | null {
72	  return value === "tiktok" || value === "instagram" ? value : null;
73	}
74	
75	Deno.serve(async (req) => {
76	  if (req.method === "OPTIONS") {
77	    return new Response(null, { status: 204, headers: corsHeaders });
78	  }
79	  if (req.method !== "POST") {
80	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
81	  }
82	
83	  const token = bearerToken(req);
84	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
85	
86	  let claims;
87	  try {
88	    claims = await verifyJwt(token);
89	  } catch {
90	    return jsonResponse(401, { error: "UNAUTHORIZED" });
91	  }
92	  if (claims.role !== "creator") {
93	    return jsonResponse(403, { error: "FORBIDDEN" });
94	  }
95	
96	  let body: AnyRequest;
97	  try {
98	    body = await req.json();
99	  } catch {
100	    return jsonResponse(400, { error: "INVALID_JSON" });
101	  }
102	
103	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
104	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
105	  if (!supabaseUrl || !serviceRoleKey) {
106	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
107	  }
108	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
109	    auth: { persistSession: false, autoRefreshToken: false },
110	  });
111	
112	  if (body.action === "add") {
113	    const platform = parsePlatform((body as AddRequest).platform);
114	    const handle = normalizeHandle((body as AddRequest).handle);
115	    if (!platform || !handle) {
116	      return jsonResponse(400, { error: "INVALID_REQUEST" });
117	    }
118	    const { data, error } = await supabase.rpc("manage_social_link", {
119	      p_user_id: claims.sub,
120	      p_action: "add",
121	      p_platform: platform,
122	      p_handle: handle,
123	      p_social_link_id: null,
124	    });
125	    if (error) {
126	      console.error("manage_social_link add rpc error", error);
127	      return jsonResponse(500, { error: "DB_ERROR" });
128	    }
129	    const result = data as
130	      | { social_link_id?: string; error?: string }
131	      | null;
132	    if (result?.error === "ALREADY_LINKED") {
133	      return jsonResponse(409, { error: "ALREADY_LINKED" });
134	    }
135	    if (result?.error === "HANDLE_TAKEN") {
136	      return jsonResponse(409, { error: "HANDLE_TAKEN" });
137	    }
138	    if (result?.error === "INVALID_REQUEST") {
139	      return jsonResponse(400, { error: "INVALID_REQUEST" });
140	    }
141	    if (!result?.social_link_id) {
142	      console.error("manage_social_link add returned unexpected shape", result);
143	      return jsonResponse(500, { error: "DB_ERROR" });
144	    }
145	    return jsonResponse(200, { social_link_id: result.social_link_id });
146	  }
147	
148	  if (body.action === "unlink") {
149	    const socialLinkId =
150	      typeof (body as UnlinkRequest).social_link_id === "string" &&
151	        UUID_RE.test((body as UnlinkRequest).social_link_id as string)
152	        ? ((body as UnlinkRequest).social_link_id as string)
153	        : null;
154	    if (!socialLinkId) {
155	      return jsonResponse(400, { error: "INVALID_REQUEST" });
156	    }
157	    const { data, error } = await supabase.rpc("manage_social_link", {
158	      p_user_id: claims.sub,
159	      p_action: "unlink",
160	      p_platform: null,
161	      p_handle: null,
162	      p_social_link_id: socialLinkId,
163	    });
164	    if (error) {
165	      console.error("manage_social_link unlink rpc error", error);
166	      return jsonResponse(500, { error: "DB_ERROR" });
