const [profile, setProfile] = useState<CreatorProfileRow | null>(null);
const [links, setLinks] = useState<SocialLink[]>([]);
const [staleLinkIds, setStaleLinkIds] = useState<Set<string>>(new Set());
const [loading, setLoading] = useState(true);
const [pendingAction, setPendingAction] = useState<string | null>(null);
const [sheetPlatform, setSheetPlatform] = useState<SocialPlatform | null>(null);

const load = useCallback(async () => {
  if (!user) return;
  setLoading(true);
  try {
    const [profileRes, linksRes, snapsRes] = await Promise.all([
      supabase
        .from('creator_profiles')
        .select('*')
        .eq('user_id', user.id)
        .maybeSingle(),
      supabase
        .from('social_links')
        .select('*')
        .eq('user_id', user.id)
        .neq('status', 'unlinked'),
      supabase
        .from('metric_snapshots')
        .select('social_link_id, status')
        .eq('is_latest', true)
        .eq('status', 'stale'),
    ]);
    if (profileRes.error) throw profileRes.error;
    if (linksRes.error) throw linksRes.error;
    if (snapsRes.error) throw snapsRes.error;
    setProfile(profileRes.data ?? null);
    setLinks(linksRes.data ?? []);
    setStaleLinkIds(new Set((snapsRes.data ?? []).map((r) => r.social_link_id)));
  } catch (err) {
    console.error('Profile load failed', err);
    showToast({ message: 'Could not load profile.', variant: 'error' });
  } finally {
    setLoading(false);
  }
}, [user, showToast]);

