  try {
    const [profileRes, linksRes] = await Promise.all([
      supabase
        .from('creator_profiles')
        .select('*')
        .eq('user_id', user.id)
        .maybeSingle(),
      supabase
        .from('social_links')
        .select('*')
        .eq('user_id', user.id)
        .neq('status', 'unlinked'),
    ]);
    if (profileRes.error) throw profileRes.error;
    if (linksRes.error) throw linksRes.error;
    const linkRows = linksRes.data ?? [];
